import org.owasp.encoder.Encode;

import java.io.*;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userInput = br.readLine();

        // Properly handling user input - encoding it before including in the HTML response
        String encodedUserInput = Encode.forHtml(userInput);

        System.out.println("<h1>Welcome, " + encodedUserInput + "!</h1>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
